.darma-loader-cssloaders-github-04 {
  display: inline-block;
  width: 56px;
  height: 56px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color, #14b8a6), var(--loader-secondary-color, #99f6e4));
  animation: darma-loader-cssloaders-github-04-squareFlip 0.85s cubic-bezier(.55,.08,.38,.97) infinite;
}
@keyframes darma-loader-cssloaders-github-04-squareFlip { 0% { transform: perspective(120px) rotateX(0) rotateY(0); } 50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); } 100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); } }

